class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private let deepLinkCoordinator = DeepLinkCoordinator()
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        window = UIWindow(windowScene: windowScene)
        
        // Set up your root view controller
        let rootVC = UIViewController() // Replace with your actual root VC
        rootVC.view.backgroundColor = .systemBackground
        let navController = UINavigationController(rootViewController: rootVC)
        window?.rootViewController = navController
        window?.makeKeyAndVisible()
        
        deepLinkCoordinator.navigator = self
        
        // Handle universal links passed at launch
        if let urlContext = connectionOptions.urlContexts.first {
            _ = deepLinkCoordinator.handleUniversalLink(urlContext.url)
        }
        
        // Handle NSUserActivity (universal links)
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            _ = deepLinkCoordinator.handleUniversalLink(url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        
        _ = deepLinkCoordinator.handleUniversalLink(url)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        _ = deepLinkCoordinator.handleUniversalLink(url)
    }
}

// MARK: - DeepLinkNavigator Conformance

extension SceneDelegate: DeepLinkNavigator {
    
    func navigateToPasswordReset(with deepLink: PasswordResetDeepLink) {
        guard let rootNavController = window?.rootViewController as? UINavigationController else {
            return
        }
        
        // Dismiss any presented view controllers first
        rootNavController.presentedViewController?.dismiss(animated: false)
        
        // Pop to root if needed
        rootNavController.popToRootViewController(animated: false)
        
        let resetVC = PasswordResetViewController(deepLink: deepLink)
        let navController = UINavigationController(rootViewController: resetVC)
        navController.modalPresentationStyle = .fullScreen
        
        // Small delay to ensure view hierarchy is ready
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {
            rootNavController.present(navController, animated: true)
        }
    }
    
    func showError(message: String) {
        guard let rootVC = window?.rootViewController else { return }
        
        let topVC = getTopViewController(from: rootVC)
        
        let alert = UIAlertController(title: "Link Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {
            topVC.present(alert, animated: true)
        }
    }
    
    private func getTopViewController(from viewController: UIViewController) -> UIViewController {
        if let presented = viewController.presentedViewController {
            return getTopViewController(from: presented)
        }
        if let nav = viewController as? UINavigationController,
           let visible = nav.visibleViewController {
            return getTopViewController(from: visible)
        }
        if let tab = viewController as? UITabBarController,
           let selected = tab.selectedViewController {
            return getTopViewController(from: selected)
        }
        return viewController
    }
}

